        when (level) {
            Level.VERBOSE -> Timber.tag(cfg.tag).v(t, message)
            Level.DEBUG -> Timber.tag(cfg.tag).d(t, message)
            Level.INFO -> Timber.tag(cfg.tag).i(t, message)
            Level.WARN -> Timber.tag(cfg.tag).w(t, message)
            Level.ERROR -> Timber.tag(cfg.tag).e(t, message)
        }
    }

    fun logException(t: Throwable, contextMessage: String? = null) {
