    fun newCorrelationId(): String = UUID.randomUUID().toString()

    internal class VerboseTree(private val cfg: Config) : Timber.Tree() {

        override fun isLoggable(tag: String?, priority: Int): Boolean {
            if (cfg.enableVerboseLogging) return true
            return priority >= Log.INFO
        }

        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            val actualTag = (tag ?: cfg.tag).take(23)
            val lines = splitToLogLines(message, cfg.maxLineLength)
            for (line in lines) {
                when (priority) {
                    Log.VERBOSE -> Log.v(actualTag, line)
                    Log.DEBUG -> Log.d(actualTag, line)
                    Log.INFO -> Log.i(actualTag, line)
                    Log.WARN -> Log.w(actualTag, line)
                    Log.ERROR -> Log.e(actualTag, line)
                    Log.ASSERT -> Log.wtf(actualTag, line)
                    else -> Log.d(actualTag, line)
                }
            }
            if (t != null) {
                val st = stackTraceToString(t)
                for (line in splitToLogLines(st, cfg.maxLineLength)) {
                    Log.e(actualTag, line)
                }
            }
        }
    }

    internal class InMemoryUploadTree(private val cfg: Config) : Timber.Tree() {
        private data class Event(
            val ts: Long,
            val priority: Int,
            val tag: String,
            val message: String
        )

        private val maxEvents = 2000
        private val buffer = ArrayDeque<Event>(maxEvents)
        private val lock = Any()
        private val executor = Executors.newSingleThreadScheduledExecutor()

        init {
            executor.scheduleAtFixedRate({ flush() }, 20, 20, TimeUnit.SECONDS)
        }

        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            val actualTag = tag ?: cfg.tag
            val full = if (t != null) message + "\n" + stackTraceToString(t) else message
            synchronized(lock) {
                if (buffer.size >= maxEvents) buffer.removeFirst()
                buffer.addLast(Event(System.currentTimeMillis(), priority, actualTag, full))
            }
        }

        fun flush() {
            val endpoint = cfg.uploadEndpointHint ?: return
            val batch: List<Event> = synchronized(lock) {
                if (buffer.isEmpty()) return
                val list = buffer.toList()
                buffer.clear()
                list
            }
            Log.i(cfg.tag, "UPLOAD FLUSH (hint=$endpoint) events=${batch.size}")
        }
    }

    class OkHttpVerboseLoggingInterceptor(
        private val correlationIdHeader: String = "X-Correlation-Id",
        private val includeRequestBody: Boolean = true,
        private val includeResponseBody: Boolean = true
    ) : Interceptor {

        override fun intercept(chain: Interceptor.Chain): Response {
            val cfg = config
            val request = chain.request()
            val correlationId = request.header(correlationIdHeader) ?: newCorrelationId()
            val reqWithId = if (request.header(correlationIdHeader) == null) {
                request.newBuilder().addHeader(correlationIdHeader, correlationId).build()
            } else request

            val reqLog = formatRequest(reqWithId, correlationId, cfg, includeRequestBody)
            d(reqLog)

            val startNs = System.nanoTime()
            val response = try {
                chain.proceed(reqWithId)
            } catch (t: Throwable) {
                e("API EXCEPTION correlationId=$correlationId ${reqWithId.method} ${reqWithId.url}\n${stackTraceToString(t)}", t)
                throw t
            }
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

            val resLog = formatResponse(response, correlationId, cfg, includeResponseBody, tookMs)
            d(resLog)

            return response
        }

        private fun formatRequest(
            request: Request,
            correlationId: String,
            cfg: Config,
            includeBody: Boolean
        ): String {
            val headers = headersToString(request.headers, cfg)
            val body = if (includeBody) bodyToString(request.body, cfg) else "<omitted>"
            return buildString {
                append("API REQUEST correlationId=").append(correlationId).append('\n')
                append(request.method).append(' ').append(request.url).append('\n')
                append("headers=").append(headers).append('\n')
                append("body=").append(body)
            }
        }

        private fun formatResponse(
            response: Response,
            correlationId: String,
            cfg: Config,
            includeBody: Boolean,
            tookMs: Long
        ): String {
            val headers = headersToString(response.headers, cfg)
            if (!includeBody) {
                return buildString {
                    append("API RESPONSE correlationId=").append(correlationId).append('\n')
                    append("code=").append(response.code).append(" message=").append(response.message).append(" tookMs=").append(tookMs).append('\n')
                    append("headers=").append(headers).append('\n')
                    append("body=<omitted>")
                }
            }

            val responseBody = response.body
            if (responseBody == null) {
                return buildString {
                    append("API RESPONSE correlationId=").append(correlationId).append('\n')
                    append("code=").append(response.code).append(" message=").append(response.message).append(" tookMs=").append(tookMs).append('\n')
                    append("headers=").append(headers).append('\n')
                    append("body=<null>")
                }
            }

            val contentType = responseBody.contentType()
            val bytes = try {
                responseBody.bytes()
            } catch (t: Throwable) {
                return buildString {
                    append("API RESPONSE correlationId=").append(correlationId).append('\n')
                    append("code=").append(response.code).append(" message=").append(response.message).append(" tookMs=").append(tookMs).append('\n')
                    append("headers=").append(headers).append('\n')
                    append("body=<failed to read: ").append(t::class.java.simpleName).append(": ").append(t.message).append(">")
                }
            }

            val bodyString = bytesToSafeString(bytes, contentType, cfg)
            val rebuiltBody = ResponseBody.create(contentType, bytes)

            val rebuilt = response.newBuilder().body(rebuiltBody).build()
            return buildString {
                append("API RESPONSE correlationId=").append(correlationId).append('\n')
                append("code=").append(rebuilt.code).append(" message=").append(rebuilt.message).append(" tookMs=").append(tookMs).append('\n')
                append("headers=").append(headers).append('\n')
                append("body=").append(bodyString)
            }
        }

        private fun bodyToString(body: RequestBody?, cfg: Config): String {
            if (body == null) return "<null>"
            return try {
                val buffer = Buffer()
                body.writeTo(buffer)
                val contentType = body.contentType()
                val bytes = buffer.readByteArray()
                bytesToSafeString(bytes, contentType, cfg)
            } catch (t: Throwable) {
                "<failed to read: ${t::class.java.simpleName}: ${t.message}>"
            }
        }

        private fun bytesToSafeString(bytes: ByteArray, contentType: MediaType?, cfg: Config): String {
            val max = cfg.maxBodyBytes.toInt().coerceAtMost(bytes.size)
            val truncated = bytes.size > max
            val slice = if (truncated) bytes.copyOfRange(0, max) else bytes
            val isText = isLikelyText(contentType)
            val base = if (isText) {
                runCatching { String(slice, Charsets.UTF_8) }.getOrElse { "<non-utf8 text (${slice.size} bytes)>" }
            } else {
                "<binary ${bytes.size} bytes contentType=${contentType ?: "unknown"} sha256=${sha256Hex(slice)}>"
            }
            return if (truncated) "$base\n<TRUNCATED totalBytes=${bytes.size} loggedBytes=$max>" else base
        }

        private fun isLikelyText(contentType: MediaType?): Boolean {
            val ct = contentType?.toString()?.lowercase(Locale.US) ?: return true
            return ct.startsWith("text/") ||
                ct.contains("json") ||
                ct.contains("xml") ||
                ct.contains("html") ||
                ct.contains("x-www-form-urlencoded") ||
                ct.contains("javascript")
        }

        private fun headersToString(headers: Headers, cfg: Config): String {
            val sb = StringBuilder()
            sb.append('{')
            for (i in 0 until headers.size) {
                val name = headers.name(i)
                val value = headers.value(i)
                val redacted = shouldRedactHeader(name, cfg) && !cfg.enableSensitiveLogging
                if (i > 0) sb.append(", ")
                sb.append('"').append(name).append('"').append(':').append('"')
                sb.append(if (redacted) "<redacted>" else value.escapeForLog())
                sb.append('"')
            }
            sb.append('}')
            return sb.toString()
        }

        private fun shouldRedactHeader(name: String, cfg: Config): Boolean {
            return cfg.redactHeaders.any { it.equals(name, ignoreCase = true) }
        }
    }

    private fun splitToLogLines(message: String, maxLen: Int): List<String> {
        if (message.isEmpty()) return listOf("")
        val out = ArrayList<String>()
        var start = 0
        while (start < message.length) {
            val end = min(message.length, start + maxLen)
            out.add(message.substring(start, end))
            start = end
        }
        return out
    }

    private fun stackTraceToString(t: Throwable): String {
        val sw = StringWriter(16_384)
        val pw = PrintWriter(sw)
        t.printStackTrace(pw)
        pw.flush()
        return sw.toString()
    }

    private fun String.escapeForLog(): String {
        return this.replace("\n", "\\n").replace("\r", "\\r").replace("\t", "\\t")
    }

    private fun String.sanitizeSql(): String {
        return this.replace(Regex("\\s+"), " ").trim()
    }

    private fun safeListToString(list: List<Any?>, allowSensitive: Boolean): String {
        if (list.isEmpty()) return "[]"
        return buildString {
            append('[')
            list.forEachIndexed { idx, v ->
                if (idx > 0) append(", ")
                append(sanitizeValue(v, allowSensitive))
            }
            append(']')
        }
    }

    private fun safeMapToString(map: Map<String, Any?>, allowSensitive: Boolean): String {
        if (map.isEmpty()) return "{}"
        return buildString {
            append('{')
            var first = true
            for ((k, v) in map) {
                if (!first) append(", ")
                first = false
                append('"').append(k).append('"').append(':')
                append(sanitizeValue(v, allowSensitive))
            }
            append('}')
        }
    }

    private fun sanitizeValue(value: Any?, allowSensitive: Boolean): String {
        if (value == null) return "null"
        return when (value) {
            is CharSequence -> {
                val s = value.toString()
                if (allowSensitive) "\"${s.escapeForLog()}\"" else "\"${maskIfSensitive(s).escapeForLog()}\""
            }
            is Number, is Boolean -> value.toString()
            else -> {
                val s = value.toString()
                if (allowSensitive) "\"${s.escapeForLog()}\"" else "\"${maskIfSensitive(s).escapeForLog()}\""
            }
        }
    }

    private fun maskIfSensitive(s: String): String {
        val trimmed = s.trim()
        if (trimmed.length <= 4) return "<redacted>"
        val looksLikeToken = trimmed.length >= 20 && trimmed.any { it.isDigit() } && trimmed.any { it.isLetter() }
        val looksLikeEmail = trimmed.contains('@') && trimmed.contains('.')
        return if (looksLikeToken || looksLikeEmail) {
            trimmed.take(2) + "…" + trimmed.takeLast(2)
        } else trimmed
    }

    private fun sanitizeUserId(s: String, allowSensitive: Boolean): String {
        if (allowSensitive) return s
        val trimmed = s.trim()
        if (trimmed.contains('@')) return maskIfSensitive(trimmed)
        return if (trimmed.length <= 3) "<redacted>" else trimmed.take(1) + "…" + trimmed.takeLast(1)
    }

    private fun sha256Hex(bytes: ByteArray): String {
        return try {
            val md = MessageDigest.getInstance("SHA-256")
            val hash = md.digest(bytes)
            hash.joinToString("") { "%02x".format(it) }
        } catch (_: Throwable) {
            "unknown"
        }
    }
}

object GlobalExceptionLogger : Thread.UncaughtExceptionHandler {

    private val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()

    fun install() {
        Thread.setDefaultUncaughtExceptionHandler(this)
    }

    override fun uncaughtException(t: Thread, e: Throwable) {
        AppLogger.e("UNCAUGHT EXCEPTION thread=${t.name}\n${e.stackTraceToStringCompat()}", e)
        defaultHandler?.uncaughtException(t, e)
    }

    private fun Throwable.stackTraceToStringCompat(): String {
        val sw = StringWriter(16_384)
        val pw = PrintWriter(sw)
        printStackTrace(pw)
        pw.flush()
        return sw.toString()
    }
}